class BMModel(SignalModel[torch.Tensor, torch.Tensor, torch.Tensor, torch.Tensor, torch.Tensor | None]):
    """Base signal model using Bloch-McConnel simulation."""

    static_off_resonance_offsets: torch.Tensor | None

    def __init__(self) -> None:
        super().__init__()
        self.sequence: BMCSequence
        self.register_buffer('static_off_resonance_offsets', None)
        self.b0 = 0.0

    def forward(
        self,
        equilibrium_magnetization: torch.Tensor,
        t1: torch.Tensor,
        t2: torch.Tensor,
        exchange_rate: torch.Tensor,
        chemical_shift: torch.Tensor | None,
    ) -> tuple[torch.Tensor]:
        """Simulate the sequence."""

        static_off_resonance = None
        if self.static_off_resonance_offsets is not None:
            static_off_resonance = torch.as_tensor(
                -2 * torch.pi * self.static_off_resonance_offsets * (magnetic_field_to_lamor_frequency(self.b0) / 1e6)
            )
        parameters = Parameters(
            equilibrium_magnetization, t1, t2, exchange_rate, chemical_shift, static_off_resonance=static_off_resonance
        )

        _, signals = self.sequence(parameters)
        if len(signals) == 1:
            return (signals[0],)
        return (torch.stack(signals, dim=0),)


class BMsimSingleBlock(BMModel):
    """Bloch-McConnell sequence with one constant saturation block per offset."""

    def __init__(
        self,
        offsets: torch.Tensor | Sequence[float],
        pulse_duration: float,
        b1: float,
        post_pulse_delay: float = 6.5e-3,
        b0: float = 3.0,
        readout_pool: int = 0,
    ) -> None:
        super().__init__()
        offsets = torch.as_tensor(offsets)
        rf_amplitude_hz = torch.as_tensor(b1 * GYROMAGNETIC_RATIO_PROTON, dtype=offsets.dtype)

        sequence = BMCSequence()
        sequence.append(ConstantRFBlock(duration=pulse_duration, rf_amplitude=rf_amplitude_hz, rf_frequency=0.0))
        sequence.append(SpoilBlock(post_pulse_delay))
        sequence.append(LongitudinalReadoutBlock(pool_index=readout_pool))

        self.static_off_resonance_offsets = offsets
        self.b0 = b0
        self.sequence = sequence


class BMsimSingleGaussianPulse(BMModel):
    """Bloch-McConnell sequence with one shaped pulse per offset."""

    def __init__(
        self,
        offsets: torch.Tensor | Sequence[float],
        pulse_envelope: torch.Tensor | Sequence[float],
        dt: float,
        post_pulse_delay: float = 6.5e-3,
        b0: float = 3.0,
        readout_pool: int = 0,
    ) -> None:
        super().__init__()
        offsets = torch.as_tensor(offsets)
        pulse_envelope = torch.as_tensor(pulse_envelope)

        sequence = BMCSequence()
        sequence.append(PiecewiseRFBlock(rf_amplitude=pulse_envelope, dt=dt))
        sequence.append(SpoilBlock(post_pulse_delay))
        sequence.append(LongitudinalReadoutBlock(pool_index=readout_pool))

        self.static_off_resonance_offsets = offsets
        self.sequence = sequence
        self.b0 = b0


class BMsimGaussianPulseTrain(BMModel):
    """Bloch-McConnell sequence with a train of shaped pulses per offset."""

    def __init__(
        self,
        offsets: torch.Tensor | Sequence[float],
        pulse_envelope: torch.Tensor | Sequence[float],
        dt: float,
        n_pulses: int,
        interpulse_delay: float,
        post_pulse_delay: float = 6.5e-3,
        b0: float = 3.0,
        readout_pool: int = 0,
    ) -> None:
        super().__init__()
        offsets = torch.as_tensor(offsets)
        pulse_envelope = torch.as_tensor(pulse_envelope)
        larmor_frequency_hz = magnetic_field_to_lamor_frequency(b0)
        offsets_hz = offsets * (larmor_frequency_hz / 1e6)
        pulse_duration = float(dt) * int(pulse_envelope.numel())

        sequence = BMCSequence()
        sequence.append(ResetBlock())
        accumulated_phase = torch.zeros_like(offsets_hz)
        for pulse_index in range(n_pulses):
            sequence.append(
                PiecewiseRFBlock(
                    rf_amplitude=pulse_envelope,
                    rf_phase=accumulated_phase[None, :],
                    rf_frequency=offsets_hz[None, :],
                    dt=dt,
                )
            )
            accumulated_phase = (accumulated_phase + 2 * torch.pi * offsets_hz * pulse_duration) % (2 * torch.pi)
            if pulse_index < n_pulses - 1:
                sequence.append(DelayBlock(interpulse_delay))
        sequence.append(SpoilBlock(post_pulse_delay))
        sequence.append(LongitudinalReadoutBlock(pool_index=readout_pool))

        self.sequence = sequence


class BMsimTwoPulseWASABI(BMModel):
    """Bloch-McConnell sequence with two block pulses per offset."""

    def __init__(
        self,
        offsets: torch.Tensor | Sequence[float],
        pulse_duration: float,
        b1: float,
        interpulse_delay: float,
        post_pulse_delay: float = 6.5e-3,
        b0: float = 3.0,
        readout_pool: int = 0,
    ) -> None:
        super().__init__()
        offsets = torch.as_tensor(offsets)
        rf_amplitude_hz = torch.as_tensor(b1 * GYROMAGNETIC_RATIO_PROTON, dtype=offsets.dtype)
        larmor_frequency_hz = magnetic_field_to_lamor_frequency(b0)
        offsets_hz = offsets * (larmor_frequency_hz / 1e6)

        sequence = BMCSequence()
        sequence.append(ResetBlock())
        for pulse_index in range(2):
            sequence.append(
                ConstantRFBlock(
                    duration=pulse_duration,
                    rf_amplitude=rf_amplitude_hz,
                    rf_frequency=offsets_hz,
                )
            )
            if pulse_index == 0:
                sequence.append(DelayBlock(interpulse_delay))
        sequence.append(SpoilBlock(post_pulse_delay))
        sequence.append(LongitudinalReadoutBlock(pool_index=readout_pool))

        self.offsets = offsets
        self.sequence = sequence


class IsochromatGradientReadoutModel(
    SignalModel[torch.Tensor, torch.Tensor, torch.Tensor, torch.Tensor, torch.Tensor | None]
):
    """Test-only model for analytic isochromat gradient comparisons."""

    def __init__(
        self,
        positions: SpatialDimension[torch.Tensor],
        gradient_blocks: Sequence[tuple[float, float, float, float]],
        initial_phase: float = 0.0,
        readout_pool: int = 0,
    ) -> None:
        super().__init__()
        self.positions = positions.apply(torch.as_tensor)
        self.initial_phase = float(initial_phase)
        self.readout_pool = readout_pool
        self.sequence = BMCSequence(
            [
                *[
                    GradientBlock(
                        duration=duration,
                        positions=self.positions,
                        gradient_z=gradient_z,
                        gradient_y=gradient_y,
                        gradient_x=gradient_x,
                    )
                    for duration, gradient_z, gradient_y, gradient_x in gradient_blocks
                ],
                AcquisitionBlock(pool_index=readout_pool),
            ]
        )

    def forward(
        self,
        equilibrium_magnetization: torch.Tensor,
        t1: torch.Tensor,
        t2: torch.Tensor,
        exchange_rate: torch.Tensor,
        chemical_shift: torch.Tensor | None,
    ) -> tuple[torch.Tensor]:
        parameters = Parameters(equilibrium_magnetization, t1, t2, exchange_rate, chemical_shift)
        state = torch.zeros(
            self.positions.z.numel(),
            parameters.n_pools,
            3,
            device=equilibrium_magnetization.device,
            dtype=equilibrium_magnetization.dtype,
        )
        state[..., self.readout_pool, 0] = torch.cos(
            torch.tensor(self.initial_phase, dtype=state.dtype, device=state.device)
        )
        state[..., self.readout_pool, 1] = torch.sin(
            torch.tensor(self.initial_phase, dtype=state.dtype, device=state.device)
        )
        _, (signal,) = self.sequence(parameters, state)
        return (signal,)


def test_gradient_block_zero_gradient_matches_delay() -> None:
    """Test that a gradient block with zero gradient matches a delay block."""
    parameters = Parameters(
        equilibrium_magnetization=torch.tensor([1.0]),
        t1=torch.tensor([1.2]),
        t2=torch.tensor([0.08]),
        exchange_rate=torch.tensor([[0.0]]),
        chemical_shift=torch.tensor([0.0]),
    )
    state = initial_state(parameters).expand(5, -1, -1).clone()
    positions = SpatialDimension(
        z=torch.linspace(-2e-3, 2e-3, 5),
        y=torch.zeros(5),
        x=torch.zeros(5),
    )
    gradient_block = GradientBlock(
        duration=4e-3,
        gradient_z=torch.tensor(0.0),
        gradient_y=torch.tensor(0.0),
        gradient_x=torch.tensor(0.0),
        positions=positions,
    )
    delay_block = DelayBlock(4e-3)

    gradient_state, _ = gradient_block(parameters, state)
    delay_state, _ = delay_block(parameters, state)

    torch.testing.assert_close(gradient_state, delay_state)


def test_isochromat_gradient_model_matches_analytic_signal() -> None:
    """Compare the isochromat gradient model to the analytic signal."""
    parameters = Parameters(
        equilibrium_magnetization=torch.tensor([1.0]),
        t1=torch.tensor([1e12]),
        t2=torch.tensor([1e12]),
        exchange_rate=torch.tensor([[0.0]]),
        chemical_shift=torch.tensor([0.0]),
    )
    positions = SpatialDimension(
        z=torch.tensor([-2e-3, 0.0, 2e-3]),
        y=torch.tensor([1e-3, -1e-3, 2e-3]),
        x=torch.tensor([0.5e-3, -0.5e-3, 1e-3]),
    )
    duration = 3e-3
    gradient_z = torch.tensor(0.012)
    gradient_y = torch.tensor(-0.007)
    gradient_x = torch.tensor(0.004)
    model = IsochromatGradientReadoutModel(
        positions=positions,
        gradient_blocks=[(duration, float(gradient_z), float(gradient_y), float(gradient_x))],
    )
    (signal,) = model(
        parameters.equilibrium_magnetization,
        parameters.t1,
        parameters.t2,
        parameters.exchange_rate,
        parameters.chemical_shift,
    )

    phase = duration * gradient_to_extra_off_resonance(gradient_z, gradient_y, gradient_x, positions)
    expected_signal = torch.exp(1j * phase).mean()
    torch.testing.assert_close(signal, expected_signal, atol=1e-5, rtol=1e-5)


def test_piecewise_rf_block_extra_off_resonance_shape() -> None:
    """Test that the piecewise RF block with extra off-resonance batches correctly."""
    parameters = Parameters(
        equilibrium_magnetization=torch.ones(5, 1),
        t1=torch.full((5, 1), 1.2),
        t2=torch.full((5, 1), 0.08),
        exchange_rate=torch.zeros(5, 1, 1),
        chemical_shift=torch.zeros(5, 1),
    )
    state = initial_state(parameters).clone()
    block = PiecewiseRFBlock(
        rf_amplitude=torch.tensor([1.0, 0.5]),
        dt=2.5e-4,
        extra_off_resonance=torch.zeros(2, 5),
    )
    out, _ = block(parameters, state)
    assert out.shape[0] == 5
    assert out.shape[-3:] == (1, 1, 3)


def test_slice_selective_rf_flat_profile_matches_piecewise_rf_block() -> None:
    """Test that the slice selective RF block with a flat profile matches the piecewise RF block."""
    parameters = Parameters(
        equilibrium_magnetization=torch.tensor([1.0]),
        t1=torch.tensor([1.2]),
        t2=torch.tensor([0.08]),
        exchange_rate=torch.tensor([[0.0]]),
        chemical_shift=torch.tensor([0.0]),
    )
    state = initial_state(parameters).expand(5, -1, -1).clone()
    positions = SpatialDimension(
        z=torch.linspace(-2e-3, 2e-3, 5),
        y=torch.zeros(5),
        x=torch.zeros(5),
    )
    amp = torch.tensor([0.3, 0.8, 1.0, 0.8, 0.3])
    profile = SliceSmoothedRectangular(fwhm_rect=1.0, fwhm_gauss=0.0)

    rf_state, _ = PiecewiseRFBlock(rf_amplitude=amp, dt=2.5e-4)(parameters, state)
    profile_state, _ = SliceSelectiveRFBlock(
        rf_amplitude=amp,
        slice_profile=profile,
        positions=positions,
        dt=2.5e-4,
    )(parameters, state)

    torch.testing.assert_close(profile_state, rf_state)


@pytest.mark.parametrize('slice_fwhm', [4e-3, 7e-3])
def test_slice_profile_approx_rf(slice_fwhm: float) -> None:
    """Test that the slice profile approximation matches the explicit RF block."""
    parameters = Parameters(
        equilibrium_magnetization=torch.tensor([1.0]),
        t1=torch.tensor([1.2]),
        t2=torch.tensor([0.08]),
        exchange_rate=torch.tensor([[0.0]]),
        chemical_shift=torch.tensor([0.0]),
    )
    n_iso = 101
    positions = SpatialDimension(
        z=torch.linspace(-1.5 * slice_fwhm, 1.5 * slice_fwhm, n_iso),
        y=torch.zeros(n_iso),
        x=torch.zeros(n_iso),
    )
    state = initial_state(parameters).expand(n_iso, -1, -1).clone()

    flip_angle = torch.deg2rad(torch.tensor(5.0))
    duration = 2e-3
    dt = 10e-6
    rf_pulse = GaussianRFPulse(fwhm_fraction=0.35)
    waveform = rf_pulse(flip_angle=flip_angle, duration=duration, dt=dt)

    gradient_z = (
        4
        * torch.log(torch.tensor(2.0))
        / (torch.pi * rf_pulse.fwhm_fraction * duration * GYROMAGNETIC_RATIO_PROTON * slice_fwhm)
    )
    extra_off_resonance = gradient_to_extra_off_resonance(gradient_z, None, None, positions)

    explicit_state, _ = PiecewiseRFBlock(
        rf_amplitude=waveform[..., None],
        dt=dt,
        extra_off_resonance=extra_off_resonance[None, :],
    )(parameters, state.unsqueeze(-3))
    explicit_state = explicit_state.squeeze(-3)

    approximate_state, _ = SliceSelectiveRFBlock(
        rf_amplitude=waveform,
        slice_profile=SliceGaussian(fwhm=slice_fwhm),
        positions=positions,
        dt=dt,
    )(parameters, state)

    explicit_profile = torch.linalg.vector_norm(explicit_state[..., 0, :2], dim=-1)
    approximate_profile = torch.linalg.vector_norm(approximate_state[..., 0, :2], dim=-1)
    explicit_profile = explicit_profile / explicit_profile.max()
    approximate_profile = approximate_profile / approximate_profile.max()

    torch.testing.assert_close(approximate_profile, explicit_profile, atol=7e-2, rtol=7e-2)


@pytest.mark.parametrize('pulse_cls', [GaussianRFPulse, SincRFPulse])
def test_slice_rf_pulse_templates_match_flip_angle_and_zero_phase(pulse_cls: type[SliceRFPulseBase]) -> None:
    """Test that the slice RF pulse templates match the flip angle and have zero intrinsic phase."""
    flip_angle = torch.tensor(torch.pi / 3)
    dt = torch.tensor(10e-6)
    duration = torch.tensor(2e-3)
    pulse = pulse_cls()
    rf, phase = pulse.rf_and_phase(flip_angle=flip_angle, duration=duration, dt=dt)
    assert rf.shape == phase.shape
    torch.testing.assert_close(phase, torch.zeros_like(phase))  # no intrinsic phase
    torch.testing.assert_close(rf, pulse(flip_angle=flip_angle, duration=duration, dt=dt))

    achieved_flip_angle = GYROMAGNETIC_RATIO_PROTON * dt * (rf * torch.exp(1j * phase)).sum()
    expected_flip_angle = torch.complex(flip_angle, torch.zeros_like(flip_angle))
    torch.testing.assert_close(achieved_flip_angle, expected_flip_angle, atol=1e-6, rtol=1e-6)


def test_gradient_to_extra_off_resonance() -> None:
    positions = SpatialDimension(
        z=torch.tensor([-1e-3, 1e-3, 2e-3]),
        y=torch.zeros(3),
        x=torch.zeros(3),
    )
    gradient_z = torch.tensor([0.01, 0.02])
    expected = 2 * torch.pi * GYROMAGNETIC_RATIO_PROTON * gradient_z[:, None] * positions.z[None, :]
    actual = gradient_to_extra_off_resonance(gradient_z, None, None, positions)
    torch.testing.assert_close(actual, expected)


