@pytest.mark.cuda
def test_bmsim_cuda() -> None:
    """Test BMsim models work on cuda devices."""
    parameters = Parameters(
        equilibrium_magnetization=torch.tensor([1.0, 5.0e-4], device='cuda'),
        t1=torch.tensor([3.0, 1.05], device='cuda'),
        t2=torch.tensor([2.0, 0.1], device='cuda'),
        exchange_rate=torch.tensor([[0.0, 50.0], [5.0e-4 * 50.0, 0.0]], device='cuda'),
        chemical_shift=torch.tensor([0.0, 1.9 * 42.5764 * 3.0], device='cuda'),
    )
    model = BMsimSingleBlock(offsets=torch.tensor([-300.0, 0.0]), pulse_duration=2.0, b1=2.0e-6).cuda()
    (signal,) = model(
        parameters.equilibrium_magnetization,
        parameters.t1,
        parameters.t2,
        parameters.exchange_rate,
        parameters.chemical_shift,
    )
    assert signal.is_cuda
    assert signal.isfinite().all()
